        "id": "01f138c58d4a1edb8fb65aa391d67889",
        "question": [
          "What was eToro's total stock trading volume last week?"
        ],
        "sql": [
          "WITH stock_volumes AS (\n",
          "  SELECT\n",
          "    date_trunc('WEEK', CAST(dp.OpenOccurred AS DATE)) AS week_start,\n",
          "    SUM(dp.Volume) AS volume\n",
          "  FROM\n",
          "    main.dwh.dim_position dp\n",
          "      INNER JOIN main.dwh.gold_sql_dp_prod_we_dwh_dbo_dim_customer_masked dc\n",
          "        ON dc.RealCID = dp.CID\n",
          "      INNER JOIN main.dwh.gold_sql_dp_prod_we_dwh_dbo_dim_instrument di\n",
          "        ON di.InstrumentID = dp.InstrumentID\n",
          "  WHERE\n",
          "    dc.IsValidCustomer = 1\n",
          "    AND dp.IsAirDrop IS NULL\n",
          "    AND di.InstrumentTypeID IN (5, 6)\n",
          "    AND dp.OpenOccurred IS NOT NULL\n",
          "    AND date_trunc('WEEK', CAST(dp.OpenOccurred AS DATE))\n",
          "      = date_trunc('WEEK', dateadd(WEEK, -1, current_date))\n",
          "  GROUP BY\n",
          "    date_trunc('WEEK', CAST(dp.OpenOccurred AS DATE))\n",
          "  UNION ALL\n",
          "  SELECT\n",
          "    date_trunc('WEEK', CAST(dp.CloseOccurred AS DATE)) AS week_start,\n",
          "    SUM(dp.VolumeOnClose) AS volume\n",
          "  FROM\n",
          "    main.dwh.dim_position dp\n",
          "      INNER JOIN main.dwh.gold_sql_dp_prod_we_dwh_dbo_dim_customer_masked dc\n",
          "        ON dc.RealCID = dp.CID\n",
          "      INNER JOIN main.dwh.gold_sql_dp_prod_we_dwh_dbo_dim_instrument di\n",
          "        ON di.InstrumentID = dp.InstrumentID\n",
          "  WHERE\n",
          "    dc.IsValidCustomer = 1\n",
          "    AND dp.IsAirDrop IS NULL\n",
          "    AND di.InstrumentTypeID IN (5, 6)\n",
          "    AND dp.CloseOccurred IS NOT NULL\n",
          "    AND date_trunc('WEEK', CAST(dp.CloseOccurred AS DATE))\n",
          "      = date_trunc('WEEK', dateadd(WEEK, -1, current_date))\n",
          "  GROUP BY\n",
          "    date_trunc('WEEK', CAST(dp.CloseOccurred AS DATE))\n",
          ")\n",
          "SELECT\n",
          "  week_start,\n",
          "  SUM(volume) AS total_stock_trading_volume_usd\n",
          "FROM\n",
          "  stock_volumes\n",
          "GROUP BY\n",
          "  week_start"
        ]
